<?php $stats=['revenue'=>0,'due'=>0,'payments'=>0,'credits'=>0]; try{ $stats['revenue']=(float)db()->query("SELECT COALESCE(SUM(total),0) FROM invoices WHERE status='paid'")->fetchColumn(); $stats['due']=(float)db()->query("SELECT COALESCE(SUM(total),0) FROM invoices WHERE status IN ('unpaid','overdue')")->fetchColumn(); $stats['payments']=(int)db()->query('SELECT COUNT(*) FROM payments')->fetchColumn(); $stats['credits']=(float)db()->query('SELECT COALESCE(SUM(balance),0) FROM customers')->fetchColumn(); }catch(Throwable $e){} ?>
